CREATE TABLE IF NOT EXISTS "Escritores" (
	"user_id" VARCHAR(255) NOT NULL,
	"nombre" VARCHAR(255) NOT NULL,
	"contraseña" VARCHAR(255) NOT NULL,
	PRIMARY KEY("user_id")
);




CREATE TABLE IF NOT EXISTS "desarrolladores" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"nombre" VARCHAR(255) NOT NULL,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "fangame" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"nombre" VARCHAR(255),
	"desarrollador_id" INTEGER NOT NULL,
	PRIMARY KEY("id")
);

COMMENT ON TABLE "fangame" IS 'joder';


CREATE TABLE IF NOT EXISTS "review" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"id_fangame" INTEGER NOT NULL,
	"contenido" VARCHAR(10000) NOT NULL,
	"url_video" VARCHAR(255) NOT NULL,
	"id_escritor" VARCHAR(255) NOT NULL,
	PRIMARY KEY("id")
);



ALTER TABLE "fangame"
ADD FOREIGN KEY("desarrollador_id") REFERENCES "desarrolladores"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "review"
ADD FOREIGN KEY("id_fangame") REFERENCES "fangame"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "review"
ADD FOREIGN KEY("id_escritor") REFERENCES "Escritores"("user_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;